  1516→static NodeInfo *Splay(SplayTreeInfo *splay_tree,const size_t depth,
  1517→  const void *key,NodeInfo **node,NodeInfo **parent,NodeInfo **grandparent)
  1518→{
  1519→  int
  1520→    compare;
  1521→
  1522→  NodeInfo
  1523→    **next;
  1524→
  1525→  register NodeInfo
  1526→    *n,
  1527→    *p;
  1528→
  1529→  n=(*node);
  1530→  if (n == (NodeInfo *) NULL)
  1531→    return(*parent);
  1532→  if (splay_tree->compare != (int (*)(const void *,const void *)) NULL)
  1533→    compare=splay_tree->compare(n->key,key);
  1534→  else
  1535→    compare=(n->key > key) ? 1 : ((n->key < key) ? -1 : 0);
  1536→  next=(NodeInfo **) NULL;
  1537→  if (compare > 0)
  1538→    next=(&n->left);
  1539→  else
  1540→    if (compare < 0)
  1541→      next=(&n->right);
  1542→  if (next != (NodeInfo **) NULL)
  1543→    {
  1544→      if (depth >= MaxSplayTreeDepth)
  1545→        {
  1546→          splay_tree->balance=MagickTrue;
  1547→          return(n);
  1548→        }
  1549→      n=Splay(splay_tree,depth+1,key,next,node,parent);
  1550→      if ((n != *node) || (splay_tree->balance != MagickFalse))
  1551→        return(n);
  1552→    }
  1553→  if (parent == (NodeInfo **) NULL)
  1554→    return(n);
  1555→  if (grandparent == (NodeInfo **) NULL)
  1556→    {
  1557→      if (n == (*parent)->left)
  1558→        {
  1559→          *node=n->right;
  1560→          n->right=(*parent);
  1561→        }
  1562→      else
  1563→        {
  1564→          *node=n->left;
  1565→          n->left=(*parent);
  1566→        }
  1567→      *parent=n;
  1568→      return(n);
  1569→    }
  1570→  if ((n == (*parent)->left) && (*parent == (*grandparent)->left))
  1571→    {
  1572→      p=(*parent);
  1573→      (*grandparent)->left=p->right;
  1574→      p->right=(*grandparent);
  1575→      p->left=n->right;
  1576→      n->right=p;
  1577→      *grandparent=n;
  1578→      return(n);
  1579→    }
  1580→  if ((n == (*parent)->right) && (*parent == (*grandparent)->right))
  1581→    {
  1582→      p=(*parent);
  1583→      (*grandparent)->right=p->left;
  1584→      p->left=(*grandparent);
  1585→      p->right=n->left;
  1586→      n->left=p;
  1587→      *grandparent=n;
  1588→      return(n);
  1589→    }
  1590→  if (n == (*parent)->left)
  1591→    {
  1592→      (*parent)->left=n->right;
  1593→      n->right=(*parent);
  1594→      (*grandparent)->right=n->left;
  1595→      n->left=(*grandparent);
  1596→      *grandparent=n;
  1597→      return(n);
  1598→    }
